3306 /// Given the following de-interleaving shufflevectors and the consuming zexts:
3307 /// ```
3308 /// %f0 = shufflevector <8 x i32> %v, <4 x i32> <i32 0, i32 2, i32 4, i32 6>
3309 /// %f1 = shufflevector <8 x i32> %v, <4 x i32> <i32 1, i32 3, i32 5, i32 7>
3310 /// %z0 = zext <4 x i32> %f0 to <4 x i64>
3311 /// %z1 = zext <4 x i32> %f1 to <4 x i64>
3312 /// ```
3313 /// We can actually bitcast the input value, `%v` first before replacing zexts
3314 /// with simple arithmetics on this new bitcast:
3315 /// ```
3316 /// %bc = bitcast <8 x i32> %v to <4 x i64>
3317 //  %z0 = and <4 x i64> %bc, splat (i64 4294967295)
3318 //  %z1 = lshr <4 x i64> %bc, splat (i64 32)
3319 /// ```
3320 /// This transformation is almost always benefitial as shufflevector is more
3321 /// expensive than normal arithmetics.
3322 bool InstCombinerImpl::foldExtractionOfVectorDeinterleave(Instruction *DI) {
3323   // This pattern involves bitcast that is not compatible with big endian.
3324   if (DL.isBigEndian())
3325     return false;
3326 
3327   using namespace PatternMatch;
3328   // The actual value that got de-interleaved.
3329   Value *DIV;
3330 
3331   auto isDeinterleaveShuffle =
3332       [](Instruction *I) -> std::pair<Value *, unsigned> {
3333     Value *V;
3334     ArrayRef<int> ShuffleMask;
3335     unsigned Index;
3336     // Match the most common form of `shufflevector <vec0>, poison, <mask>`.
3337     // Not sure if we'll see `shufflevector poison, <vec0>, <mask>` in the
3338     // future.
3339     if (match(I, m_Shuffle(m_Value(V), m_Undef(), m_Mask(ShuffleMask))) &&
3340         ShuffleVectorInst::isDeInterleaveMaskOfFactor(ShuffleMask, 2, Index) &&
3341         Index < 2)
3342       return {V, Index};
3343     return {nullptr, UINT_MAX};
3344   };
3345 
3346   // Try matching shufflevector. The point here is to just find the first
3347   // shufflevector. We'll find other shufflevectors later.
3348   DIV = isDeinterleaveShuffle(DI).first;
3349   // Try matching llvm.vector.deinterleave2.
3350   if (!DIV) {
3351     if (!match(DI, m_Deinterleave2(m_Value(DIV))) ||
3352         !all_of(DI->users(), [](User *Usr) -> bool {
3353           auto *EV = dyn_cast<ExtractValueInst>(Usr);
3354           return EV && EV->getNumIndices() == 1;
3355         }))
3356       return false;
3357   }
3358 
3359   auto *InputVecTy = dyn_cast<VectorType>(DIV->getType());
3360   if (!InputVecTy)
3361     return false;
3362   auto *InElementTy = dyn_cast<IntegerType>(InputVecTy->getElementType());
3363   if (!InElementTy)
3364     return false;
3365   if (!InputVecTy->getElementCount().isKnownEven())
3366     return false;
3367 
3368   // {Field instruction, Field index}
3369   SmallVector<std::pair<Instruction *, unsigned>, 4> Fields;
3370   if (isa<ShuffleVectorInst>(DI)) {
3371     for (auto *Usr : DIV->users()) {
3372       auto *FieldI = dyn_cast<Instruction>(Usr);
3373       if (!FieldI)
3374         continue;
3375       auto [V, Index] = isDeinterleaveShuffle(FieldI);
3376       if (V != DIV)
3377         continue;
3378       assert(Index < 2);
3379       Fields.push_back({FieldI, Index});
3380     }
3381   } else {
3382     // llvm.vector.deinterleave2.
3383     for (User *Field : DI->users()) {
3384       auto *FieldI = cast<ExtractValueInst>(Field);
3385       unsigned FieldIdx = *FieldI->idx_begin();
3386       assert(FieldIdx < 2);
3387       Fields.push_back({FieldI, FieldIdx});
3388     }
3389   }
3390 
3391   // We commit the transformation only if all the field users can be replaced,
3392   // otherwise the primary de-interleaving construction, regardless of
3393   // llvm.vector.deinterleave2 or shufflevectors, will still be there.
3394   SmallVector<Instruction *, 4> Field0Replacements;
3395   SmallVector<Instruction *, 4> Field1Replacements;
3396   for (auto [Field, FieldIdx] : Fields) {
3397     for (User *FieldUsr : Field->users()) {
3398       auto *ZExt = dyn_cast<ZExtInst>(FieldUsr);
3399       if (!ZExt)
3400         return false;
3401       // Only if it's doubling the element size.
3402       if (ZExt->getDestTy() != ZExt->getSrcTy()->getExtendedType())
3403         return false;
3404       if (FieldIdx)
3405         Field1Replacements.push_back(ZExt);
3406       else
3407         Field0Replacements.push_back(ZExt);
3408     }
3409   }
3410 
3411   // Double the element size but half the vector length.
3412   auto *BitcastedTy = VectorType::getExtendedElementVectorType(InputVecTy);
3413   BitcastedTy = VectorType::getHalfElementsVectorType(BitcastedTy);
3414   Value *Bitcast = Builder.CreateBitCast(DIV, BitcastedTy);
3415   APInt Mask = InElementTy->getMask();
3416   Value *NewField0 =
3417       Builder.CreateAnd(Bitcast, Mask.zext(Mask.getBitWidth() * 2));
3418   Value *NewField1 = Builder.CreateLShr(Bitcast, InElementTy->getBitWidth());
3419 
3420   for (Instruction *I : Field0Replacements)
3421     replaceInstUsesWith(*I, NewField0);
3422   for (Instruction *I : Field1Replacements)
3423     replaceInstUsesWith(*I, NewField1);
3424 
3425   return true;
3426 }
