3364 /// Matches either L && R or L || R,
3365 /// either one being in the either binary or logical form.
3366 /// Note that the latter form is poison-blocking.
3367 template <typename LHS, typename RHS, bool Commutable = false>
3368 inline auto m_LogicalOp(const LHS &L, const RHS &R) {
3369   return m_CombineOr(
3370       LogicalOp_match<LHS, RHS, Instruction::And, Commutable>(L, R),
